from functools import lru_cache

# Correct: pure function, bounded input, no side effects
@lru_cache(maxsize=1000)
def expensive_computation(input_data: str) -> str:
    return perform_heavy_calculation(input_data)

# Invalidate when underlying data changes
expensive_computation.cache_clear()

from cachetools import TTLCache, cached
import threading

# TTL cache with thread safety
cache = TTLCache(maxsize=1000, ttl=300)
cache_lock = threading.Lock()

@cached(cache, lock=cache_lock)
def get_config(key: str) -> dict:
    return load_config_from_db(key)

from cachetools import TTLCache
import threading

class WarmableCache:
    def __init__(self, loader, ttl: int = 300):
        self.cache = TTLCache(maxsize=10000, ttl=ttl)
        self.loader = loader
        self.lock = threading.Lock()

    def get(self, key: str):
        # First check (no lock) — fast path for cache hits
        if key not in self.cache:
            with self.lock:
                # Second check (with lock) — prevents duplicate loads
                if key not in self.cache:
                    self.cache[key] = self.loader(key)
        return self.cache[key]

    def warm(self, keys: list):
        """Preload known hot keys before traffic arrives."""
        for key in keys:
            self.cache[key] = self.loader(key)

# Usage
config_cache = WarmableCache(
    loader=lambda key: load_config_from_db(key),
    ttl=300
)

# Warm on startup with known hot keys
config_cache.warm(["feature_flags", "rate_limits", "allowed_origins"])

from functools import lru_cache
import redis
import json

redis_client = redis.Redis(host='localhost', port=6379, decode_responses=True)

class MultiLayerProductCache:
    """L1: process-local lru_cache, L2: Redis, L3: database."""

    # L1: Process-local cache for hot products (40% hit rate)
    @lru_cache(maxsize=1000)
    def _get_hot_product_local(self, product_id: str):
        return None  # Cache miss triggers L2 lookup

    # L2: Redis distributed cache
    def _get_product_redis(self, product_id: str):
        cached = redis_client.get(f"product:{product_id}")
        if cached:
            return json.loads(cached)
        return None

    # L3: Database
    def _get_product_db(self, product_id: str):
        return self.db.products.find_one({"_id": product_id})

    def get_product(self, product_id: str):
        # Try L1 (local, sub-ms)
        data = self._get_hot_product_local(product_id)

        # Try L2 (Redis, 1-5ms)
        if not data:
            data = self._get_product_redis(product_id)

        # Try L3 (Database, 10-100ms)
        if not data:
            data = self._get_product_db(product_id)
            if data:
                redis_client.setex(f"product:{product_id}", 3600, json.dumps(data))

        return data

    def update_product(self, product_id: str, updates: dict):
        self.db.products.update_one({"_id": product_id}, {"$set": updates})
        # Invalidate all cache layers — top-down
        self._get_hot_product_local.cache_clear()
        redis_client.delete(f"product:{product_id}")

# Typical metrics: L1 hit 40% (5ms), L2 hit 50% (15ms), L3 hit 10% (50ms)
